#!/usr/bin/env Rscript
args<-commandArgs(trailingOnly=TRUE);get<-function(k,d=NULL){i<-match(k,args);if(is.na(i))return(d);args[i+1]};a<-readRDS(get('--analysis'));out<-get('--outdir');dir.create(file.path(out,'probe_lists'),recursive=TRUE,showWarnings=FALSE);assay<-function(n)if(inherits(a,'SummarizedExperiment'))SummarizedExperiment::assay(a,n)else a[[n]];b<-assay('beta');m<-assay('mvalue');d<-assay('detection');mincall<-as.numeric(get('--min-detection-rate'));maxmiss<-as.numeric(get('--max-missing-rate'));reason<-rep('',nrow(b));names(reason)<-rownames(b);reason[colMeans(is.na(d)|d<=.05)<mincall]<-'detection_rate';reason[colMeans(is.na(b))>maxmiss]<-ifelse(reason[colMeans(is.na(b))>maxmiss]=='','missingness',paste(reason[colMeans(is.na(b))>maxmiss],'missingness',sep=';'))
lst<-get('--exclusion-list');if(!is.null(lst)){p<-scan(lst,what='',quiet=TRUE);reason[names(reason)%in%p]<-ifelse(reason[names(reason)%in%p]=='','user_list',paste(reason[names(reason)%in%p],'user_list',sep=';'))};keep<-reason=='';rem<-data.frame(probe_id=names(reason)[!keep],reason=reason[!keep]);write.table(rem,file.path(out,'probe_lists','removed_probes.tsv'),sep='\t',row.names=FALSE,quote=FALSE);sum<-data.frame(stage=c('input','removed','retained'),probes=c(nrow(b),sum(!keep),sum(keep)));write.table(sum,file.path(out,'filtering_summary.tsv'),sep='\t',row.names=FALSE,quote=FALSE)
b<-b[keep,,drop=FALSE];m<-m[keep,,drop=FALSE];d<-d[keep,,drop=FALSE];writegz<-function(x,n){z<-gzfile(file.path(out,n),'wt');write.table(cbind(probe_id=rownames(x),x),z,sep='\t',row.names=FALSE,quote=FALSE);close(z)};writegz(b,'beta_values.filtered.tsv.gz');writegz(m,'m_values.filtered.tsv.gz');if(inherits(a,'SummarizedExperiment'))a<-SummarizedExperiment::SummarizedExperiment(assays=list(beta=b,mvalue=m,detection=d),colData=SummarizedExperiment::colData(a),rowData=SummarizedExperiment::rowData(a)[keep,]);else{a$beta<-b;a$mvalue<-m;a$detection<-d};saveRDS(a,file.path(out,'analysis_filtered.rds'))
